create table public.lenders (id uuid default gen_random_uuid() primary key, created_at timestamptz default now() not null, updated_at timestamptz default now() not null, lender_name text not null, common_name text, asset_class_appetite text[] default '{}', geography text, deal_size_min numeric, deal_size_max numeric, ltv_standard numeric, ltv_stretch numeric, rate_range_low numeric, rate_range_high numeric, arrangement_fee text, exit_fee text, turnaround_speed text, current_status text check (current_status in ('hungry','selective','quiet','changing')), key_contacts jsonb default '[]'::jsonb, recent_deal_experience text, suleman_notes text);